UPDATE tx_global
SET status = #{status},
error_code = #{errorCode},
error_msg = #{errorMsg}
WHERE tx_id = #{txId}

UPDATE tx_global
SET next_run_at = #{nextRunAt}
WHERE tx_id = #{txId}

UPDATE tx_global
SET version = version + 1
WHERE tx_id = #{txId}
AND version = #{version}

mapper.select:
SELECT *
FROM tx_global
WHERE status IN

    #{s}

AND next_run_at <= #{now}
ORDER BY next_run_at ASC, id ASC
LIMIT #{limit}

